VALUES
  ('pukao-6f0ba476-moex-00119', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲將名貴項鍊出賣於乙，約定三日後交付。交付前，甲先將項鍊借於好友丙佩戴數日，甲商得乙、 丙同意，由乙受讓甲對丙之返還請求權，以代交付。丙卻於使用時，不慎遺失而被丁拾得。下列 敘述，何者正確？', '["甲交付項鍊於丙使用時，甲仍為項鍊之直接占有人，丙為間接占有人", "丁因拾獲遺失項鍊而原始取得項鍊所有權", "乙同意甲之指示交付方式後，乙取得項鍊所有權", "甲得依所有物返還請求權之規定，對拾得人丁請求返還項鍊"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00120', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於天然孳息之敘述，何者錯誤？', '["甲在其自家後院種植芒果樹，芒果熟成後掉落在後院內，屬甲所有", "甲將其土地租給乙種植芒果樹，芒果熟成後掉落在該土地上，歸乙所有", "甲在其自家後院種植芒果樹，芒果熟成後掉落在鄰居乙之後院內，歸乙所有", "甲在其自家後院種植芒果樹，芒果熟成後掉落在公有馬路上，屬國家所有"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00121', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲登記為A屋之所有人，乙以所有之意思占有A屋，下列敘述，何者正確?', '["視為甲為A屋之所有人", "視為乙為A屋之所有人", "推定甲為A屋之所有人", "推定乙為A屋之所有人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00122', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲男乙女為夫妻，甲、乙有一女丙。甲之父為丁、丁之弟為戊。丙與戊之親屬關係為何？', '["三親等直系姻親", "三親等旁系血親", "四親等旁系血親", "四親等旁系姻親"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00123', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列何者，應列入夫妻之剩餘財產？', '["遺贈所得", "因遺失物拾得所取得之財產", "彩券中獎所得", "因無主物先占而取得之財產"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00124', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '關於離婚後未成年子女權利義務之行使或負擔，下列敘述，何者錯誤？', '["權利義務之行使或負擔，應優先由父母依協議決定", "未行使或負擔權利義務之父母一方，仍有與子女之會面交往權", "父母均不適合行使權利時，應另選定監護人，並由其負擔扶養費用", "離婚不影響父母之扶養義務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00125', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲有二子乙與丙，乙、丁為夫妻但膝下無子，丙有一子戊。某日，甲、乙遇難雙亡，但乙先於甲 五分鐘死亡，下列敘述，何者正確？', '["丁對於甲之遺產得主張代位繼承", "丙若於甲生前已為預先拋棄繼承，戊即得對甲之遺產主張代位繼承", "戊為甲之直系血親卑親屬，但不得對乙之遺產主張代位繼承", "丙將甲之遺囑變造，將原為A宗教儀式改為B宗教儀式，戊得對甲之遺產主張代位繼承"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00126', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲有三名子女乙、丙、丁。乙與戊結婚後，甲認為乙是長男，甲應該要住到乙新買的房子。乙於 是提議甲之遺產必須由乙全部繼承，甲才可以住過來。甲找來丙與丁，分別讓丙、丁寫下對甲之 遺產拋棄繼承之書面。甲死亡後，下列敘述，何者正確？', '["甲既已與乙約定，故丙、丁拋棄繼承有效", "丙、丁於甲生前所為之拋棄繼承，並無效力", "丙、丁未以該書面為拋棄繼承之登記前，拋棄尚不生效力", "丙、丁之拋棄繼承，自甲死亡時起發生效力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00127', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於密封遺囑之敘述，何者錯誤？', '["遺囑人立密封遺囑時，由遺囑人指定二人以上之見證人，向公證人提出", "密封遺囑應由遺囑人於遺囑上簽名後，將其密封，於封縫處簽名", "密封遺囑之內容，應由本人自寫，不得由他人繕寫", "密封遺囑，如不具備密封遺囑所定之方式，而具備自書遺囑之方式者，有自書遺囑之效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "961fb1a39bf6", "answer_pdf_sha1": "47c8124c3b97", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "416", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00128', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-113-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'essay', '請說明我國「所得基本稅額條例」關於 113 年度營利事業排除適用的範
